INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_001', 'ru', 'БОН = хороший + ЖУР = день → ''добрый день!''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_002', 'ru', 'Звучит как ''мерси'' — мы уже знаем это слово!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_003', 'ru', 'Звучит как ''уи'' — ''у-у-и, согласен!''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_004', 'ru', 'Похоже на русское ''нон-стоп'' → приставка отрицания');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_005', 'ru', '''Ша'' — кот шикает на вас: ''шшш!''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_006', 'ru', 'МЕ-ЗОН → ''мезонин'' — этаж в доме');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_007', 'ru', 'Звучит как ''О'' — нарисуйте O, это капля воды');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_008', 'ru', 'МАН-ЖЕ → человек (man) жуёт → ест');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_009', 'ru', 'ДОР-МИР → дормитория (dormitory) — место для сна');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_010', 'ru', 'ФАМ → ''фамилия'' — женщина в семье');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_011', 'ru', 'ОМ → ''гомо сапиенс'' — человек');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_012', 'ru', 'ГРАН → ''грандиозный'' — большой, великий');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_013', 'ru', 'ПЁТИ → ''петит'' — маленький (уже есть в русском!)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_014', 'ru', 'РУЖ → ''румяна'' (rouge) — красный цвет на щеках');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_015', 'ru', 'БЛЁ → ''блю'' (blue) по-английски, похоже!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_016', 'ru', 'ПАР-ЛЕ → ''парламент'' — место, где говорят');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_017', 'ru', 'АЛЛЕ → ''Алле!'' — вперёд! (слышно на стадионах)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_018', 'ru', 'ВЁНИР → ''вени, види, вици'' = я пришёл...');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_019', 'ru', 'ПЕН → звучит как ''пан'' (хлеб по-испански)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_020', 'ru', 'ВЕН → ''винтаж'' происходит от слова ''вино''!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_021', 'ru', 'БО → ''бо'' = красивый мужчина (есть в английском)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_022', 'ru', 'МЭНТНАН → МЕН = рука + ТЕНАН = держит → держит время СЕЙЧАС');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_023', 'ru', 'ТУЖУР → ТУ = все + ЖУР = дни → каждый день, всегда');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_024', 'ru', 'ЖАМЭ → ЖАМ = замок → дверь никогда не откроется');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_025', 'ru', 'ПЁ = может + ЭТРЬ = быть → ''может быть''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_026', 'ru', 'КОМ + ПРАНДР → ''компрехенд'' — постичь умом');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_027', 'ru', 'САВУАР-ФЕР → знание дела (savoir-faire уже в русском!)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_028', 'ru', 'КОНЭТР → ''коннесёр'' = знаток — тот, кто знает!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_029', 'ru', 'ВИЛЬ → ''вилла'' — загородный дом в городе');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_030', 'ru', 'ТРАВАЙ → ''трэвел'' (travel) от travail → путешествие = труд');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_031', 'ru', 'ШУА-ЗИР → ''чойс'' (choice) — выбор!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_032', 'ru', 'ДИФИСИЛЬ → похоже на ''difficult'' — трудный');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_033', 'ru', 'ФАСИЛЬ → ''фасилити'' — лёгкость, удобство');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_034', 'ru', 'СУВАН → СУ = под + ВАН = ветер → ''под ветром'' — часто дует');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_035', 'ru', 'АНСАМБЛЬ → ''ансамбль'' — группа, играющая ВМЕСТЕ!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_036', 'ru', 'ПЕРДР → ''пердита'' (perdita) — потерянная');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_037', 'ru', 'ТРУВЕ → ''трувер'' — средневековый поэт, который ''находил'' песни');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_038', 'ru', 'АТАНДР → ''аттенд'' раньше значило ''ждать''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_039', 'ru', 'КРУАР → ''кредо'' (creed) — во что ты веришь');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_040', 'ru', 'ЛИР → ''легибл'' (legible) — что можно прочитать');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_041', 'ru', 'ЭКРИР → ''скриб'' (scribe) — тот, кто пишет');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_042', 'ru', 'КЕСТЬОН → почти как ''квестион'' (question) — вопрос');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_043', 'ru', 'РЕПОНС → ''респонс'' (response) — ответ');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_044', 'ru', 'ПАНСЕ → ''пенсив'' (pensive) — задумчивый');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_045', 'ru', 'САНТИР → ''сентимент'' (sentiment) — чувство');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_046', 'ru', 'ШЁМЭН → ''шеминэ'' (cheminée) — камин, путь дыма');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_047', 'ru', 'ЛЮМЬЕР → ''люминесценция'' — свечение, свет. Братья Люмьер изобрели кино!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_048', 'ru', 'НУВО → ''нуво'' уже в русском: арт-нуво, божоле нуво');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_049', 'ru', 'ПРОПР → ''пропер'' (proper) — чистый, правильный');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_050', 'ru', 'ЛИБР → ''либерти'' (liberty) — свобода!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_051', 'ru', 'КОНФЬЯНС → ''конфиденция'' — доверие, секрет');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_052', 'ru', 'КРЭНТ → КРЭНДР = бояться → крэнт = сам страх');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_053', 'ru', 'ПУРТАН → ПУР = для + ТАН = столько → ''при всём этом, однако''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_054', 'ru', 'КАН МЕМ → МЕМ = тот же → ''всё то же самое, всё равно''');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_055', 'ru', 'АН ЭФФЕ → ''эффект'' — действительно, так и есть');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_056', 'ru', 'ДЕМАРШ → ''демарш'' уже есть в русском! — решительный шаг');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_057', 'ru', 'МЕ = плохо + ФЬЕ = доверять → плохо доверять');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_058', 'ru', 'РЕЗУДР → ''резолюция'' — решение проблемы');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_059', 'ru', 'ПРЕ = до + ВЁНИР = прийти → прийти заранее = предупредить');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_060', 'ru', 'КОМПОРТМАН → ''компорт'' — как себя ведёшь');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_061', 'ru', 'АН ЖЁ → ''в игре'' → что на кону');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_062', 'ru', 'ДЕЗОРМЭ → ДЕ = от + ОР = сейчас → отныне');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_063', 'ru', 'ДЕ КЁ → ДЕ = от (момента) + КЁ = что → как только');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_064', 'ru', 'СЁ РАНДР КОНТ → дать себе отчёт → осознать');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_065', 'ru', 'НЮАНС → слово ''нюанс'' пришло в русский из французского!');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_066', 'ru', 'МЕ + КОНЭТР → плохо знать = не понимать');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_067', 'ru', 'АБУТИР → АБУТ = конец → дойти до конца/результата');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_068', 'ru', 'МИЗ АН ЁВЕР → МИЗА = поставить + В ДЕЛО → реализовать');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_069', 'ru', 'ТЕЛЬ КЁ → ТЕЛЬ = такой → такой как (пример)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_070', 'ru', 'ПАРВЁНИР → ПАР = через + ВЁНИР = прийти → прийти через = достичь');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_071', 'ru', 'САВЕРЭ → ''верифицировать'' — подтвердить как истину');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_072', 'ru', 'АМБИГЮИТЭ → ''амбигуитет'' — двусмысленность (почти как в русском!)');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_073', 'ru', 'ДЭКЛЯНШЕ → ДЕ = от + КЛЕНШ = щеколда → ''снять щеколду'', запустить');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_074', 'ru', 'ПРЕКОНИЗЕ → ПРЕ + КОНИЗЭ → советовать заранее = рекомендовать');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_075', 'ru', 'ПЕРТИНАНС → ''пертинентный'' = уместный, по делу');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_076', 'ru', 'АТТЕНЮЭ → ''аттенюация'' = ослабление сигнала');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_077', 'ru', 'ЭССОР → ''взлёт'' — как птица взмывает вверх');
INSERT INTO vocab_hint (vocab_id, lang, text) VALUES ('fr_078', 'ru', 'МЕТР АН ЭКЗЕРГ → вынести на видное место, подчеркнуть');
